(668, 167, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'TIDAK adanya data tentang penggunaan moda transportasi alternatif yang digunakan oleh pengunjung.', 4, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(669, 168, 4, 'terpenuhi_sepenuhnya', 'Terpenuhi Sepenuhnya', 'Desa Wisata melakukan promosi untuk meningkatkan peluang bersepeda dan berjalan kaki. Promosi telah diagendakan secara rutin. Program tersebut didukung dokumentasi tertulis.', 1, '2026-06-07 19:12:07', '2026-06-13 12:18:00', NULL),
(670, 168, 3, 'sebagian_terpenuhi', 'Sebagian Terpenuhi', 'Desa Wisata melakukan promosi untuk meningkatkan peluang bersepeda dan berjalan kaki. Promosi telah diagendakan secara rutin. BELUM terdokumentasikan.', 2, '2026-06-07 19:12:07', '2026-06-13 12:18:00', NULL),
(671, 168, 2, 'kurang_terpenuhi', 'Kurang Terpenuhi', 'Desa Wisata melakukan promosi untuk meningkatkan peluang bersepeda dan berjalan kaki. Namun tidak diagendakan secara rutin. BELUM terdokumentasikan.', 3, '2026-06-07 19:12:07', '2026-06-13 12:18:00', NULL),
(672, 168, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'Desa wisata TIDAK melakukan promosi peluang bersepeda dan berjalan kaki.', 4, '2026-06-07 19:12:07', '2026-06-13 12:18:00', NULL),
(673, 169, 4, 'terpenuhi_sepenuhnya', 'Terpenuhi Sepenuhnya', 'Terdapat prioritas pasar bagi pengunjung yang mudah diakses melalui pilihan transportasi yang pendek dan lebih berkelanjutan. Telah disosialisasikan secara luas kepada pengunjung. Dan sudah dilaksanakan secara konsisten.', 1, '2026-06-07 19:12:07', '2026-06-13 12:19:13', NULL),
(674, 169, 3, 'sebagian_terpenuhi', 'Sebagian Terpenuhi', 'Terdapat prioritas pasar bagi pengunjung yang mudah diakses melalui pilihan transportasi yang pendek dan lebih berkelanjutan. Telah disosialisasikan secara luas kepada pengunjung. Belum dilaksanakan secara konsisten.', 2, '2026-06-07 19:12:07', '2026-06-13 12:19:13', NULL),
(675, 169, 2, 'kurang_terpenuhi', 'Kurang Terpenuhi', 'Terdapat prioritas pasar bagi pengunjung yang mudah diakses melalui pilihan transportasi yang pendek dan lebih berkelanjutan. Namun belum disosialisasikan secara luas kepada pengunjung. Belum dilaksanakan secara konsisten.', 3, '2026-06-07 19:12:07', '2026-06-13 12:19:13', NULL),
(676, 169, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'Desa wisata TIDAK memprioritaskan pilihan transportasi berkelanjutan.', 4, '2026-06-07 19:12:07', '2026-06-13 12:19:13', NULL),
(677, 170, 4, 'terpenuhi_sepenuhnya', 'Terpenuhi Sepenuhnya', 'Terdapat dorongan kepada sektor publik dan badan-badan usaha pariwisata untuk memprioritaskan transportasi berdampak-rendah dalam operasi mereka. Telah diberikan insentif secara konsisten kepada sektor publik dan badan-badan usaha pariwisata tersebut.', 1, '2026-06-07 19:12:07', '2026-06-13 12:20:29', NULL),
(678, 170, 3, 'sebagian_terpenuhi', 'Sebagian Terpenuhi', 'Terdapat dorongan kepada sektor publik dan badan-badan usaha pariwisata untuk memprioritaskan transportasi berdampak-rendah dalam operasi mereka. Telah diberikan insentif kepada sektor publik dan badan-badan usaha pariwisata tersebut. Belum dilaksanakan secara konsisten.', 2, '2026-06-07 19:12:07', '2026-06-13 12:20:29', NULL),
(679, 170, 2, 'kurang_terpenuhi', 'Kurang Terpenuhi', 'Terdapat dorongan kepada sektor publik dan badan-badan usaha pariwisata untuk memprioritaskan transportasi berdampak-rendah dalam operasi mereka. BELUM diberikan insentif kepada sektor publik dan badan-badan usaha pariwisata tersebut.', 3, '2026-06-07 19:12:07', '2026-06-13 12:20:29', NULL),
(680, 170, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'TIDAK terdapat dorongan kepada sektor publik dan badan-badan usaha pariwisata untuk memprioritaskan transportasi berdampak-rendah dalam operasi mereka.', 4, '2026-06-07 19:12:07', '2026-06-13 12:20:29', NULL),
(681, 171, 4, 'terpenuhi_sepenuhnya', 'Terpenuhi Sepenuhnya', 'Terdapat lahan parkir yang cukup dan memadai.', 1, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(682, 171, 3, 'sebagian_terpenuhi', 'Sebagian Terpenuhi', 'Terdapat lahan parkir yang cukup namun kurang memadai .', 2, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(683, 171, 2, 'kurang_terpenuhi', 'Kurang Terpenuhi', 'Terdapat lahan parkir yang namun kurang banyak dan kurang memadai.', 3, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(684, 171, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'TIDAK terdapat lahan parkir.', 4, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(685, 172, 4, 'terpenuhi_sepenuhnya', 'Terpenuhi Sepenuhnya', 'Desa wisata memiliki upaya untuk meminimalkan polusi suara yang telah disosialisasikan kepada badan usaha pariwisata. Sudah TERDOKUMENTASIKAN.', 1, '2026-06-07 19:12:07', '2026-06-13 08:29:49', NULL),
(686, 172, 3, 'sebagian_terpenuhi', 'Sebagian Terpenuhi', 'Desa wisata memiliki upaya untuk meminimalkan polusi suara yang telah disosialisasikan kepada badan usaha pariwisata. BELUM terdokumentasikan.', 2, '2026-06-07 19:12:07', '2026-06-13 08:29:49', NULL),
(687, 172, 2, 'kurang_terpenuhi', 'Kurang Terpenuhi', 'Desa wisata memiliki upaya untuk meminimalkan polusi suara. Namun belum disosialisasikan kepada badan usaha pariwisata. BELUM terdokumentasikan.', 3, '2026-06-07 19:12:07', '2026-06-13 08:29:49', NULL),
(688, 172, 1, 'tidak_terpenuhi', 'Tidak Terpenuhi', 'Desa wisata TIDAK memiliki upaya untuk meminimalkan polusi suara.', 4, '2026-06-07 19:12:07', '2026-06-13 08:29:49', NULL);
INSERT INTO `survey_questions` (`id`, `survey_template_id`, `aspect`, `code`, `question_text`, `document_hint`, `sort_order`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 1, 'KELEMBAGAAN', 'Q01', 'Pengelola Desa/Kampung Wisata memiliki struktur pengurus wisata (secara legal) dan disahkan oleh pihak terkait (tingkat desa, kabupaten/ provinsi). Dibuktikan dengan dokumen struktur kepengurusan berikut ketugasan yang diperankan masing-masing bagian.', 'SK Pengelola yang telah disahkan; Job Deskripsi', 1, '2026-06-07 19:12:07', '2026-06-12 15:13:03', NULL),
(2, 1, 'KELEMBAGAAN', 'Q02', 'Sudah merumuskan dan menetapkan AD/ART yang berlaku kepada pengelola yang terlibat dalam aktivitas Desa/Kampung Wisata. Dibuktikan dengan dokumen AD/ART.', 'AD/ART yang telah disahkan pihak berwenang', 2, '2026-06-07 19:12:07', '2026-06-12 15:35:37', NULL),
(3, 1, 'KELEMBAGAAN', 'Q03', 'Terdapat pencatatan keuangan yang jelas dan transparan yang dilaporkan dalam jangka waktu tertentu. Dibuktikan dengan dokumen pencatatan keuangan.', 'Laporan keuangan baik secara manual maupun digital', 3, '2026-06-07 19:12:07', '2026-06-12 15:36:27', NULL),
(4, 1, 'KELEMBAGAAN', 'Q04', 'Terdapat pencatatan kunjungan wisatawan di Desa/Kampung Wisata ( < 5 Tahun terakhir). Disajikan dengan tabel/ chart/ secara baik.', 'Data kunjungan wisatawan yang sudah dianalisis', 4, '2026-06-07 19:12:07', '2026-06-12 15:38:13', NULL),
(5, 1, 'KELEMBAGAAN', 'Q05', 'Pengelola pariwisata memiliki dokumen perencanaan Desa/Kampung Wisata dan sudah ada yang dijalankan sebagian program yang direncanakan. Ada dokumen perencanaan pengembangan desa wisata berikut dengan bukti- bukti pelaksanaannya.', 'Dokumen perencanaan dan program kerja yang sudah dijalankan', 5, '2026-06-07 19:12:07', '2026-06-12 15:39:13', NULL),
(6, 1, 'KELEMBAGAAN', 'Q06', 'Pengelola wisata secara rutin melakukan pertemuan Desa/Kampung Wisata. Dibuktikan dengan notulensi pertemuan.', 'Surat undangan rapat, daftar hadir, dan notulensi rapat', 6, '2026-06-07 19:12:07', '2026-06-12 15:39:53', NULL),
(7, 1, 'KELEMBAGAAN', 'Q07', 'Adanya sistem pergantian kepengurusan yang dipilih melalui musyawarah yang jabatannya dibatasi dalam jangka waktu tertentu.', 'Dokumen rapat pemilihan dan pergantian kepengurusan', 7, '2026-06-07 19:12:07', '2026-06-12 15:40:38', NULL),
(8, 1, 'KELEMBAGAAN', 'Q08', 'Terdapat keseimbangan/kesetaraan dalam komposisi pengelola Desa/Kampung Wisata berdasarkan kelompok usia dan gender.', 'Dokumen struktur pengelola yang mencatat komposisi secara detail', 8, '2026-06-07 19:12:07', '2026-06-13 12:05:14', NULL),
(9, 1, 'KELEMBAGAAN', 'Q09', 'Pengelola Desa/Kampung Wisata memiliki sistem untuk menampung masukan (saran,pesan,kesan) dari wisatawan.', 'Data feedback wisatawan, baik secara manual maupun digital', 9, '2026-06-07 19:12:07', '2026-06-12 20:03:21', NULL),
(10, 1, 'KELEMBAGAAN', 'Q10', 'Dapat menyediakan pemandu lokal berbahasa asing jika kedatangan wisatawan asing (terdapat pengelola desa/kampung wisata yang bisa berbahasa asing menjadi nilai tambah).', 'Data jumlah pemandu wisata berbahasa asing, baik yang sudah tersertifikai maupun belum', 10, '2026-06-07 19:12:07', '2026-06-12 20:04:22', NULL),
(11, 1, 'KEMITRAAN', 'Q11', 'Desa/Kampung Wisata memiliki kemitraan dengan pemangku kepentingan pihak eksternal mencakup pentahelix (ABCGM). Kemitraan Desa/Kampung Wisata pada ranah operasional.', 'MoU dengan stakeholder eksternal', 11, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(12, 1, 'KEMITRAAN', 'Q12', 'Pengelola Desa/Kampung Wisata memiliki kemitraan dengan stakeholder internal (Perangkat Desa, Perangkat dukuh, Karang Taruna, PKK, KWT, LMDH). Dibuktikan dengan dokumen tertulis. Kemitraan Desa/Kampung Wisata dalam konteks operasional, diantaranya pengelolaan destinasi.', 'MoU dengan stakeholder internal', 12, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(13, 1, 'KEMITRAAN', 'Q13', 'Sifat kemitraan dalam berkontribusi untuk pengembangan Desa/Kampung Wisata. Dibuktikan dengan bukti kemitraan.', 'Implementasi MoU dengan mitra', 13, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(14, 1, 'KEMITRAAN', 'Q14', 'Kemitraan berlangsung jangka panjang dan berkelanjutan.', 'Implementasi MoU dengan mitra', 14, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(15, 1, 'KEMITRAAN', 'Q15', 'Kemitraan berdampak pada peningkatan kualitas bidang ekonomi, sosial, budaya, dan lingkungan.', 'Implementasi MoU dengan mitra', 15, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(16, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q16', 'Kebijakan yang mengatur upaya pelestarian lingkungan hidup (bisa ditambahkan dengan adanya peraturan tertulis/SK/Perdes, dsb).', 'Dokumen kebijakan pelestarian lingkungan dalam pengelolaan DEWI', 16, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(17, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q17', 'Kebijakan yang mengatur upaya pelestarian budaya.', 'Dokumen kebijakan pelestarian budaya dalam pengelolaan DEWI', 17, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(18, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q18', 'Adanya kelembagaan yang mengurusi pelestarian lingkungan di Desa/Kampung Wisata.', 'Dokumen struktur lembaga yang bertanggung jawab dalam pelestarian lingkungan', 18, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(19, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q19', 'Adanya kelembagaan yang mengurusi pelestarian budaya di Desa/Kampung Wisata (dibuktikan dengan SK, HAKI, Nomer Induk Kebudayaan).', 'Dokumen struktur lembaga yang bertanggung jawab dalam pelestarian budaya', 19, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(20, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q20', 'Adanya fasilitas guna melestarikan budaya dan lingkungan di Desa/Kampung Wisata (latihan dan pertunjukan).', 'Data fasilitas yang diperuntukkan untuk pelestarian budaya dan dokumen pengelolaannya', 20, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(21, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q21', 'Pelestarian budaya lokal melalui event/pementasan.', 'Data pelaksanaan event, meliputi agenda event, event yang sudah dan akan dilaksanakan', 21, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(22, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q22', 'Adanya kegiatan pelatihan budaya rutin.', 'Data program pelatihan budaya', 22, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(23, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q23', 'Paket wisata yang mendukung kegiatan pelestarian lingkungan dan budaya', 'Data paket wisata yang mendukung pelestarian budaya', 23, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(24, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q24', 'Adanya sistem pengelolaan dan atau pengolahan limbah cair dan padat di Desa/Kampung Wisata (pemilahan sampah rumah tangga, bank sampah, pengolahan limbah cair sederhana).', 'Data program pengelolaan sampah', 24, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(25, 1, 'LINGKUNGAN DAN PELESTARIAN', 'Q25', 'Ada pengetahuan, pemahaman serta ada dukungan kelembagaan terkait kerentanan terhadap bahaya di sekitar kawasan.', 'Dokumen Penanggulangan Resiko Bencana. Ada signage khusus: jalur evakuasi, ancaman bencana, titik kumpul, shelter (jika ada) Ada lembaga penanggulangan bencana di tingkat desa/kampung', 25, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(26, 1, 'PERAN SERTA MASYARAKAT', 'Q26', 'Tingkat keterlibatan masyarakat dalam program pengelolaan Desa/Kampung Wisata.', 'Data tingkat keterlibatan masyarakat dan bidang keterlibatan', 26, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(27, 1, 'PERAN SERTA MASYARAKAT', 'Q27', 'Keterlibatan masyarakat dalam pemodalan untuk mendukung pengembangan Desa/Kampung Wisata.', 'Data pemodalan yang berasal dari masyarkat setempat', 27, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(28, 1, 'PERAN SERTA MASYARAKAT', 'Q28', 'Penyerapan tenaga kerja sebagai bagian dari pemberdayaan masyarakat.', 'Data peluang usaha baru dan penyerapan tenaga kerja', 28, '2026-06-07 19:12:07', '2026-06-13 12:12:44', NULL),
(29, 1, 'ATRAKSI WISATA', 'Q29', 'Daya tarik wisata alam yang dimiliki Desa/Kampung Wisata.', 'Profile Desa/Kampung Wisata', 29, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(30, 1, 'ATRAKSI WISATA', 'Q30', 'Daya tarik wisata budaya yang dimiliki Desa/Kampung Wisata.', 'Profile Desa/Kampung Wisata', 30, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(31, 1, 'ATRAKSI WISATA', 'Q31', 'Terdapat daya tarik wisata buatan.', 'Profile Desa/Kampung Wisata, foto terkait, narasi terkait wisata buatan.', 31, '2026-06-07 19:12:07', '2026-06-13 11:13:06', NULL),
(32, 1, 'ATRAKSI WISATA', 'Q32', 'Terdapat paket wisata yang menghubungkan antar daya tarik alam, budaya, dan buatan.', 'Brosur Desa/Kampung Wisata', 32, '2026-06-07 19:12:07', '2026-06-13 09:10:07', NULL),
(33, 1, 'ATRAKSI WISATA', 'Q33', 'Terdapat produk hasil industri kreatif (pengolahan produk lokal menjadi makanan, kerajinan tangan dsb) yang dapat mendukung kegiatan pariwisata.', 'Foto terkait, narasi tentang produk yang ada', 33, '2026-06-07 19:12:07', '2026-06-13 09:11:51', NULL),
(34, 1, 'ATRAKSI WISATA', 'Q34', 'Terdapat kehidupan sosial budaya (living culture) yang khas melengkapi atraksi. Masih dijalankan tradisi yang dilestarikan dan telah dikemas menjadi atraksi budaya pendukung Desa/Kampung Wisata (event tahunan yang rutin dijalankan).', 'Foto terkait dan narasi tentang kehiduoan sosial budaya yag melengkapi atraksi.', 34, '2026-06-07 19:12:07', '2026-06-13 09:13:03', NULL),
(35, 1, 'ATRAKSI WISATA', 'Q35', 'Terdapat event/kegiatan yang rutin dilaksanakan (misal pasar sabtu-minggu) di Desa/Kampung Wisata menyajikan sajian setempat dan telah menjadi atraksi pariwisata.', 'Foto terkait dan narasi event', 35, '2026-06-07 19:12:07', '2026-06-13 09:13:45', NULL),
(36, 1, 'ATRAKSI WISATA', 'Q36', 'Memiliki karakter daya tarik khusus yang menjadi USP (Unique Selling Point ).', 'Foto terkait dan narasi tentang USP yang ada', 36, '2026-06-07 19:12:07', '2026-06-13 09:14:35', NULL),
(37, 1, 'AKSESBILITAS', 'Q37', 'Tersedianya rambu penunjuk arah menuju dan di dalam Desa/Kampung Wisata.', NULL, 37, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(38, 1, 'AKSESBILITAS', 'Q38', 'Tersedianya akses jalan menuju dan di dalam Desa/Kampung Wisata dalam kondisi baik, tidak berlobang, dan mudah dilalui berbagai moda transportasi.', NULL, 38, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(39, 1, 'AKSESBILITAS', 'Q39', 'Memiliki peta kawasan yang mudah ditemukan wisatawan di kawasan desa.', NULL, 39, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(40, 1, 'AKSESBILITAS', 'Q40', 'Terdapat informasi titik lokasi di Google Maps yang disertai dengan gambar, data kontak yang bisa dihubungi, dan rating kepuasan pelayanan.', NULL, 40, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
