(42, 1, 'AKSESBILITAS', 'Q42', 'Tersedianya titik kumpul dan papan petunjuk menuju titik kumpul untuk evakuasi jika terjadi bencana.', NULL, 42, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(43, 1, 'AKSESBILITAS', 'Q43', 'Tersedianya layanan untuk wisatawan dengan disabilitas.', NULL, 43, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(44, 1, 'AMENITAS PENDUKUNG', 'Q44', 'Fasilitas dan proses penyediaan makanan dan minuman yang hiegienis.', NULL, 44, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(45, 1, 'AMENITAS PENDUKUNG', 'Q45', 'Penyediaan makanan dan minuman khas, yang menjadi keunikan Desa/Kampung Wisata.', NULL, 45, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(46, 1, 'AMENITAS PENDUKUNG', 'Q46', 'Terdapat kantor sekretariat Desa/Kampung Wisata.', NULL, 46, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(47, 1, 'AMENITAS PENDUKUNG', 'Q47', 'Terdapat gerai yang menjual souvenir atau produk lokal wisata.', NULL, 47, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(48, 1, 'AMENITAS PENDUKUNG', 'Q48', 'Terdapat jaringan telekomunikasi/ internet di Desa/Kampung Wisata.', NULL, 48, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(49, 1, 'AMENITAS PENDUKUNG', 'Q49', 'Terdapat fasilitas dan mekanisme pertolongan pertama untuk menangani krisis kesehatan atau kecelakaan dalam kegiatan wisata.', NULL, 49, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(50, 1, 'AMENITAS PENDUKUNG', 'Q50', 'Fasilitas kesehatan (kotak P3K) dan alat pemadam kebakaran tersedia di Desa/Kampung Wisata yang dirawat/evaluasi secara berkala.', NULL, 50, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
(51, 1, 'AMENITAS PENDUKUNG', 'Q51', 'Terdapat jaringan arus listrik cadangan ketika terjadi pemadaman (genset, tenaga listrik sederhana).', NULL, 51, '2026-06-07 19:12:07', '2026-06-07 19:12:07', NULL),
